// 去除字符串中的所有空白字符
std::string remove_whitespace(const std::string& s) {
    std::string result;
    for (char c : s) {
        if (!isspace(c)) {
            result += c;
        }
    }
    return result;
}

// 十六进制字符转字节
uint8_t hex_char_to_byte(char c) {
    if (c >= '0' && c <= '9') return c - '0';
    if (c >= 'A' && c <= 'F') return c - 'A' + 10;
    if (c >= 'a' && c <= 'f') return c - 'a' + 10;
    return 0; // 处理无效字符
}

// 十六进制字符串转字节数组
std::vector<uint8_t> hex_to_bytes(const std::string& hex) {
    std::vector<uint8_t> bytes;
    std::string hex_clean = remove_whitespace(hex);

    if (hex_clean.length() % 2 != 0) {
        hex_clean = "0" + hex_clean; // 处理奇数长度，前面补0
    }

    for (size_t i = 0; i < hex_clean.length(); i += 2) {
        uint8_t high = hex_char_to_byte(hex_clean[i]);
        uint8_t low = hex_char_to_byte(hex_clean[i + 1]);
        bytes.push_back((high << 4) | low);
    }

    return bytes;
}

// 字节数组转十六进制字符串
std::string bytes_to_hex(const std::vector<uint8_t>& bytes) {
    std::stringstream ss;
    ss << std::hex << std::setfill('0');
    for (uint8_t b : bytes) {
        ss << std::setw(2) << static_cast<int>(b);
    }
    return ss.str();
}

