// 构造函数，接受8字节密钥
DES::DES(const std::vector<uint8_t>& key) {
    if (key.size() != 8) {
        throw std::invalid_argument("密钥长度必须为8字节");
    }

    // 将8字节密钥转换为64位整数
    uint64_t key64 = 0;
    for (int i = 0; i < 8; ++i) {
        key64 |= static_cast<uint64_t>(key[i]) << (8 * (7 - i));
    }

    // 生成子密钥
    key_schedule(key64);
}

// 置换函数
uint64_t DES::permute(uint64_t input, const int* table, int input_size, int output_size) {
    uint64_t result = 0;

    for (int i = 0; i < output_size; ++i) {
        int position = table[i] - 1; // 表中的位置是1-based，转换为0-based
        uint64_t bit = (input >> (input_size - position - 1)) & 1;
        result |= bit << (output_size - i - 1);
    }

    return result;
}

// 左移函数
uint32_t DES::left_shift(uint32_t value, int shift) {
    return ((value << shift) | (value >> (28 - shift))) & 0x0FFFFFFF; // 保持28位
}

// 密钥调度：生成16个子密钥
void DES::key_schedule(const uint64_t key) {
    // 应用PC-1置换，得到56位密钥
    uint64_t pc1 = permute(key, PC1_TABLE, 64, 56);

    // 将56位密钥分为左右两部分，各28位
    uint32_t left = (pc1 >> 28) & 0x0FFFFFFF;
    uint32_t right = pc1 & 0x0FFFFFFF;

    // 生成16个子密钥
    for (int i = 0; i < 16; ++i) {
        // 左移
        left = left_shift(left, SHIFT_TABLE[i]);
        right = left_shift(right, SHIFT_TABLE[i]);

        // 合并左右部分，得到56位
        uint64_t combined = (static_cast<uint64_t>(left) << 28) | right;

        // 应用PC-2置换，得到48位子密钥
        subkeys[i] = permute(combined, PC2_TABLE, 56, 48);
    }
}

// F函数
uint32_t DES::f_function(uint32_t right, uint64_t subkey) {
    // 扩展置换，32位扩展到48位
    uint64_t expanded = permute(right, E_TABLE, 32, 48);

    // 与子密钥异或
    uint64_t xor_result = expanded ^ subkey;

    // S盒替换，48位转换为32位
    uint32_t sbox_output = 0;
    for (int i = 0; i < 8; ++i) {
        // 每个S盒处理6位
        uint8_t block = (xor_result >> (42 - i * 6)) & 0x3F;

        // 计算行和列
        int row = ((block >> 5) << 1) | (block & 1);
        int col = (block >> 1) & 0x0F;

        // S盒替换
        uint8_t sbox_value = S_BOX[i][row][col];

        // 结果放入sbox_output
        sbox_output = (sbox_output << 4) | sbox_value;
    }

    // P盒置换
    return permute(sbox_output, P_TABLE, 32, 32);
}

// 加密单个64位块
uint64_t DES::encrypt_block(uint64_t block) {
    // 初始置换
    uint64_t ip = permute(block, IP_TABLE, 64, 64);

    // 分为左右两部分，各32位
    uint32_t left = (ip >> 32) & 0xFFFFFFFF;
    uint32_t right = ip & 0xFFFFFFFF;

    // 16轮Feistel网络
    for (int i = 0; i < 16; ++i) {
        uint32_t temp = right;
        right = left ^ f_function(right, subkeys[i]);
        left = temp;
    }

    // 最后一轮后，左右部分不交换
    uint64_t combined = (static_cast<uint64_t>(right) << 32) | left;

    // 最终置换
    return permute(combined, FP_TABLE, 64, 64);
}

// 解密单个64位块
uint64_t DES::decrypt_block(uint64_t block) {
    // 初始置换
    uint64_t ip = permute(block, IP_TABLE, 64, 64);

    // 分为左右两部分，各32位
    uint32_t left = (ip >> 32) & 0xFFFFFFFF;
    uint32_t right = ip & 0xFFFFFFFF;

    // 16轮Feistel网络，使用逆序的子密钥
    for (int i = 15; i >= 0; --i) {
        uint32_t temp = right;
        right = left ^ f_function(right, subkeys[i]);
        left = temp;
    }

    // 最后一轮后，左右部分不交换
    uint64_t combined = (static_cast<uint64_t>(right) << 32) | left;

    // 最终置换
    return permute(combined, FP_TABLE, 64, 64);
}

// ECB模式加密
std::vector<uint8_t> DES::encrypt_ecb(const std::vector<uint8_t>& plaintext) {
    std::vector<uint8_t> ciphertext;

    // 计算需要填充的字节数
    size_t padding = 8 - (plaintext.size() % 8);
    if (padding == 0) padding = 8;

    // 处理每个64位块
    for (size_t i = 0; i < plaintext.size() + padding; i += 8) {
        uint64_t block = 0;

        // 填充当前块
        for (int j = 0; j < 8; ++j) {
            if (i + j < plaintext.size()) {
                block |= static_cast<uint64_t>(plaintext[i + j]) << (8 * (7 - j));
            } else {
                // PKCS#5填充
                block |= static_cast<uint64_t>(padding) << (8 * (7 - j));
            }
        }

        // 加密块
        uint64_t encrypted_block = encrypt_block(block);

        // 将加密后的块添加到密文中
        for (int j = 0; j < 8; ++j) {
            ciphertext.push_back((encrypted_block >> (8 * (7 - j))) & 0xFF);
        }
    }

    return ciphertext;
}

// ECB模式解密
std::vector<uint8_t> DES::decrypt_ecb(const std::vector<uint8_t>& ciphertext) {
    std::vector<uint8_t> plaintext;

    if (ciphertext.size() % 8 != 0) {
        throw std::invalid_argument("密文长度必须是8字节的倍数");
    }

    // 处理每个64位块
    for (size_t i = 0; i < ciphertext.size(); i += 8) {
        uint64_t block = 0;

        // 从密文中提取块
        for (int j = 0; j < 8; ++j) {
            block |= static_cast<uint64_t>(ciphertext[i + j]) << (8 * (7 - j));
        }

        // 解密块
        uint64_t decrypted_block = decrypt_block(block);

        // 将解密后的块添加到明文中
        for (int j = 0; j < 8; ++j) {
            plaintext.push_back((decrypted_block >> (8 * (7 - j))) & 0xFF);
        }
    }

    // 移除PKCS#5填充
    if (!plaintext.empty()) {
        uint8_t padding = plaintext.back();
        if (padding <= 8) {
            plaintext.resize(plaintext.size() - padding);
        }
    }

    return plaintext;
}

// 从环境变量或标准输入读取输入
std::string read_input(const std::string& env_name, const std::string& prompt) {
    char* env_value = getenv(env_name.c_str());
    std::string input;

    if (env_value != nullptr) {
        input = remove_whitespace(env_value);
        if (!input.empty()) {
            return input;
        }
    }

    // 环境变量不存在或为空，从标准输入读取
    std::cout << prompt;
    std::cin >> input;

    return remove_whitespace(input);
}

